package plugins.openldap.acl.editor.org.apache.directory.studio.openldap.config.acl;

public class OpenLdapAclValueWithContext { private IBrowserConnection connection ; private IEntry entry ; private int precedence = - 1 ; private String aclValue ; private AclItem aclItem ; private OpenLdapAclDialog aclDialog ; private static final OpenLdapAclParser parser = new OpenLdapAclParser ( ) ; public OpenLdapAclValueWithContext ( IBrowserConnection connection , IEntry entry , int precedence , String aclValue ) { this . connection = connection ; this . entry = entry ; this . precedence = precedence ; this . aclValue = aclValue ; try { aclItem = parser . parse ( aclValue ) ; } catch ( ParseException e ) { e . printStackTrace ( ) ; } } public String getAclValue ( ) { return aclValue ; } public IBrowserConnection getConnection ( ) { return connection ; } public IEntry getEntry ( ) { return entry ; } public int getPrecedence ( ) { return precedence ; } public boolean hasPrecedence ( ) { return precedence != - 1 ; } public AclItem getAclItem ( ) { return aclItem ; } public OpenLdapAclDialog getAclDialog ( ) { return aclDialog ; } public void setAclDialog ( OpenLdapAclDialog aclDialog ) { this . aclDialog = aclDialog ; } public String toString ( ) { if ( aclValue != null ) { if ( precedence != - 1 ) { return "{" + precedence + "}" + aclValue ; } else { return aclValue ; } } return "" ; } }